import{_ as r,o as p,c as t,ag as n}from"./chunks/framework.DXGyWiRo.js";const i="/images/uebung025.jpg",s="/images/uebung026.jpg",c=JSON.parse('{"title":"Übung Lektion 17","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/uebung17.md","filePath":"lektionen/uebung17.md"}'),a={name:"lektionen/uebung17.md"};function o(l,e,h,g,m,d){return p(),t("div",null,[...e[0]||(e[0]=[n('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="ubung-lektion-17" tabindex="-1">Übung Lektion 17 <a class="header-anchor" href="#ubung-lektion-17" aria-label="Permalink to &quot;Übung Lektion 17&quot;">​</a></h1><p>A) Setzen Sie in folgenden Sätzen das Verb ein und übersetzen Sie:</p><p>१. ब्राह्मनो ऽनृतं न ... (ब्रू । वच् । वद्) । ब्रवीति । वक्ति । वदति । Ein Brahmane spricht keine Unwahrheit.</p><p>२. क्षत्रियो जनान् ... (पा । रक्ष्) । पाति । रक्षति । Ein Kṣatriya hütet die Leute.</p><p>३. बलवद्योधो द्विजारीन् ... (जि । हन् । युध्) । द्विजारीञ्जयति । द्विजारीन्हन्ति । युध्यते । Der mächtige Kämpfer besiegt / tötet / bekämpft die Feinde der Zweimalgeborenen.</p><p>४. ब्राह्मणकविर्लोकेश्वरम् ... (स्तु । यज्) । स्तौति । स्तुते । यजते । यजति । Der brahmanische Dichter preist den HERRN der Welt. ... opfert als Opferherr / in fremdem Auftrag dem HERRN der Welt</p><p>५. अग्निर्यज्ञान्नम् ... (अद् । दह्) । अत्ति । दहति । Das Feuer verzehrt / verbrennt die Speise</p><p>६. बालवैश्यो धेनुम् ... (दुह् । रक्ष् । पा) । दोग्धि । दुग्धे । रक्षति । पाति । Der junge Vaiṣya melkt / hütet die Kuh.</p><p>७. द्विजदासो मृगमार्गेण ब्राह्मणग्रामम् ... (गम् । इ । पद्) । गच्छति । एति । पद्यते । Ein Diener der Zweimalgeborenen geht auf dem Wildwechsel ind Brahmanendorf.</p><p>८. द्विजदासः शूद्रस् ... (अस् २ । भू) । द्विजदासः शूद्रो ऽस्ति । ... शूद्रो भवति । Ein Śūdra ist Knecht der Zweimalgeborenen.</p><p>९. बालब्राह्मणी ... (रुद् । आस् । मृ) । रोदिति । बालब्राह्मण्याते । म्रियते । Die kleine Brahmanin weint / sitzt / stirbt.</p><p>१०. साधुजनो ऽधर्मम् ... (द्विष् । न कृ) । द्वेष्टि । द्विष्टे । न करोति । न कुरुते ।Eine Gute Person hasst das Unrecht. ... tut kein Unrecht.</p><p>B) Setzen Sie in den in A) gebildeten Sätzen Agens und Verb in den Plural</p><p>१. ब्राह्मनो ऽनृतं न ... (ब्रू । वच् । वद्) । ब्राह्मणा अनृतण् न ब्रुवन्ति । plur. von वच् kommt nicht vor । वदन्ति</p><p>२. क्षत्रियो जनान् ... (पा । रक्ष्) । क्षत्रिया जनान्पान्ति । रक्षन्ति ।</p><p>३. बलवद्योधो द्विजारीन् ... (जि । हन् । युध्) । बलवद्योधा द्विजारीञ्जयन्ति । ... द्विजारीन्घन्ति । युध्यन्ते ।</p><p>४. ब्राह्मणकविर्लोकेश्वरम् ... (स्तु । यज्) । ब्राह्मणकवयो लोकेश्वरं स्तुवन्ति । स्तुवते । यजन्ति । यजन्ते ।</p><p>५. अग्निर्यज्ञान्नम् ... (अद् । दह्) । अग्नयो यज्ञान्नमदन्ति । दहन्ति ।</p><p>६. बालवैश्यो धेनुम् ... (दुह् । रक्ष् । पा) । बालवैश्या धेनुं दुहन्ति । दुहते । रक्षन्ति । पान्ति ।</p><p>७. द्विजदासो मृगमार्गेण ब्राह्मणग्रामम् ... (गम् । इ । पद्) । द्विजदासा मृगमार्गेण ब्राह्मणग्रामं गच्छन्ति । यन्ति । पद्यन्ते ।</p><p>८. द्विजदासः शूद्रस् ... (अस् २ । भू) । द्विजदासाः शूद्राः सन्ति । ... शूद्रा भवन्ति ।</p><p>९. बालब्राह्मणी ... (रुद् । आस् । मृ) । बालब्राह्मण्या रुदन्ति । बालब्राह्मण्य आसते । बालब्राह्मण्यो म्रियन्ते ।</p><p>१०. साधुजनो ऽधर्मम् ... (द्विष् । न कृ) । साधुजनो ऽधर्मं द्विषन्ति । द्विषते । न कुर्वन्ति । न कुर्वते ।</p><p><img src="'+i+'" alt=""><br> Abb.: बालब्राह्मणी रोदिति<br> विद्यारम्भः<br> [Bildquelle: ToreaJade. -- <a href="http://www.flickr.com/photos/toreajade/52085380/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/toreajade/52085380/</a>. -- Zugriff am 2008-12-22. -- <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, share alike)]</p><p>Übersetzen Sie folgende Verbformen und geben Sie die dazugehörige Wurzel an:</p><p>१. अदन्ति अद् 2P sie essen</p><p>२. सन्ति अस् 2P sie sind</p><p>३. आसते आस् 2Ā sie sitzen</p><p>४. यन्ति इ 2P sie gehen</p><p>५. इच्छति इष् 6P er wünscht</p><p>६. कुर्वते कृ 8U sie tun im eigenen Interesse</p><p>७. गच्छन्ति गम् 1P sie gehen</p><p>८. जायते जन् 4Ā er entsteht</p><p>९. जयति जि 1P er siegt</p><p>१०. तनोति तन् 8U er spannt auf</p><p>११. दहति दह् 1P er verbrennt</p><p>१२. दोग्धि दुह् 2U er melkt</p><p>१३. पश्यति दृश् 4P er sieht</p><p>१४. द्विष्टे द्विष् 2U er hasst</p><p>१५. नयन्ति नी 1U sie führen</p><p>१६. नृत्यति नृत् 4P er tanzt</p><p>१७. पद्यन्ते पद् 4Ā sie schreiten</p><p>१८. पिबति पा 1P er trinkt</p><p>१९. पान्ति पा 2P sie hüten</p><p>२०. पृच्छति प्रच्छ् 6P er fragt</p><p>२१. बुध्यन्ते बुध् 4Ā sie erwachen</p><p>२२. ब्रवीति ब्रू 2U er spricht</p><p>२३. भवन्ति भू 1P sie werden</p><p>२४. मन्यते मन् 4Ā er meint</p><p>२५. मुञ्चन्ति मुच् 6U sie befreien</p><p>२६. म्रियन्ते मृ 4Ā sie sterben</p><p>२७. यजते यज् 1U er opfert als Opferherr</p><p>२८. युध्यन्ते युध् 4Ā sie kämpfen</p><p>२९. रक्षति रक्ष् 1P er hütet</p><p>३०. रोदिति रुद् 2P er heult</p><p>३१. लभते लभ् 1Ā er erhält</p><p>३२. वक्ति वच् 2P er spricht</p><p>३३. वदति वद् 1P er spricht</p><p>३४. शृणोति श्रु 5P er hört</p><p>३५. स्तौति स्तु 2U er lobt</p><p>३६. स्मरति स्मृ 1P er vergegenwärtigt</p><p>३७. हन्ति हन् 2P er erschlägt</p><p>३८. अश्नुवते अश् 5Ā sie erreichen</p><p>३९. कुप्यते कुप् 4P es wird gezürnt</p><p>४० कर्षन्ति कृष् 6U sie ziehen</p><p>४१. उद्यते वद् 1P es wird gesagt</p><p>४२. सहन्ते सह् 1Ā sie ertragen</p><p>४३. सिच्यन्ते सिच् 6U sie werden beträufelt</p><p>४४. आप्नोति आप् 5P er erreicht</p><p>४५. जीव्यते जीव् 1P es wird gelebt</p><p>४६. दिश्यन्न्ते दिश् 6U sie werden gezeigt</p><p><img src="'+s+'" alt=""><br> Abb.: शृणोति<br> Bangalore<br> [Bildquelle: mattlogelin. -- <a href="http://www.flickr.com/photos/mattlogelin/401785290/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/mattlogelin/401785290/</a>. -- Zugriff am 2008-12-22. -- <a href="http://creativecommons.org/licenses/by-nc/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung)]</p>',73)])])}const b=r(a,[["render",o]]);export{c as __pageData,b as default};
